head.script:
scwin.strFromDate = $c.date.getServerDateTime("yyyyMM")+"01";
scwin.strToDate = $c.date.getServerDateTime("yyyyMMdd");// 현재일자를 구한다.
scwin.memJson = $c.data.getMemInfo();
scwin.privAdmin = $c.data.getMemInfo("privAdmin");
scwin.isStarted = true;  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 처리)
//-------------------------------------------------------------------------
// 전역변수를 선언한다.
